sql:
SELECT asset_id, tags
FROM assets
WHERE file_size = (SELECT MAX(file_size) FROM assets);

SELECT COUNT(DISTINCT user_id) AS unique_users, MAX(access_date) AS last_access_date
FROM access_logs
WHERE asset_id = 1;

SELECT T2.user_name
FROM uploads AS T1
JOIN users AS T2 ON T1.user_id = T2.user_id
WHERE T1.file_size = (
    SELECT MIN(file_size) FROM uploads
);

